INSERT INTO templates_v2 (id, name, type, version, template_json, active, created_at, updated_at, created_by)
VALUES 
('seed-letter-01', 'Official NOC / Internship Request Letter', 'Internship', 1, 
 '{"format_html": "<div style=\"font-family: ''Times New Roman'', Times, serif; font-size: 15px; line-height: 1.6; color: #000; padding: 40px; max-width: 800px; margin: 0 auto;\"><div style=\"display: flex; justify-content: space-between; margin-bottom: 40px;\"><div><strong>Ref. No.</strong> TAT/{{branch_code}}/{{ref_no}}/2026</div><div><strong>Date:</strong> {{date}}</div></div><div style=\"margin-bottom: 25px;\">To,<br/><br/>The {{company_hr_title}},<br/>{{company_name}}<br/>{{company_address}}</div><div style=\"margin-bottom: 25px;\"><strong>Subject: Application for Internship Opportunity</strong></div><div style=\"margin-bottom: 20px;\">Dear Sir/Madam,</div><p style=\"margin-bottom: 20px; text-align: justify;\">I am reaching out to formally request an internship opportunity on behalf of <strong>Mr./Ms. {{student_name}}</strong>, a dedicated <strong>{{year}}</strong> B. Tech student majoring in <strong>{{branch_name}}</strong>. <strong>Mr./Ms. {{student_name}}</strong> is currently enrolled in the academic session <strong>{{session}}</strong> at Trident Academy of Technology, Bhubaneswar, and holds registration number <strong>{{reg_no}}</strong>.</p><p style=\"margin-bottom: 20px; text-align: justify;\">Trident Academy of Technology is proud to be affiliated with Biju Patnaik University of Technology, Rourkela, Odisha, and accredited by the All India Council of Technical Education (AICTE), New Delhi.</p><p style=\"margin-bottom: 20px; text-align: justify;\">We kindly ask for your consideration in allowing <strong>Mr./Ms. {{student_name}}</strong> to apply for an internship within your esteemed organization. The proposed duration for this internship is approximately <strong>{{duration}}</strong>, starting from <strong>{{start_date}}</strong>.</p><p style=\"margin-bottom: 30px; text-align: justify;\">We firmly believe that an internship opportunity at your organization would offer <strong>Mr./Ms. {{student_name}}</strong> invaluable hands-on experience, perfectly aligning with their academic pursuits and future career aspirations.</p><p style=\"margin-bottom: 50px;\">Thank you sincerely for reviewing our request.</p><div style=\"margin-bottom: 20px;\">Yours faithfully,<br/><br/><br/><br/><strong>{{hod_name}}</strong><br/>{{hod_designation}} ({{branch_code}}),<br/>Trident Academy of Technology,<br/>Mail: {{hod_email}} | Mobile: {{hod_mobile}}</div></div>", "form_fields": []}', 
 1, '2026-03-22T00:00:00Z', '2026-03-22T00:00:00Z', 'system');
